namespace sv_414da6cf30fe4d31a5fa8da9b89ae54e.Components;

public enum ScreenSize
{
    Mobile,
    Tablet,
    Desktop
}

@implements IAsyncDisposable
@inject IJSRuntime JS

<CascadingValue Value="currentSize">
    @ChildContent
</CascadingValue>

@code {
    [Parameter]
    public RenderFragment? ChildContent { get; set; }

    private ScreenSize currentSize = ScreenSize.Desktop;
    private IJSObjectReference? module;
    private DotNetObjectReference<ScreenSizeProvider>? objRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            objRef = DotNetObjectReference.Create(this);
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/ScreenSizeProvider.razor.js");
            await module.InvokeVoidAsync("initialize", objRef);
        }
    }

    [JSInvokable]
    public void OnResize(int width)
    {
        var newSize = Categorize(width);
        if (newSize != currentSize)
        {
            currentSize = newSize;
            StateHasChanged();
        }
    }

    private static ScreenSize Categorize(int width) => width switch
    {
        < 768 => ScreenSize.Mobile,
        < 1024 => ScreenSize.Tablet,
        _ => ScreenSize.Desktop
    };

    public async ValueTask DisposeAsync()
    {
        if (module is not null)
        {
            await module.InvokeVoidAsync("dispose");
            await module.DisposeAsync();
        }
        objRef?.Dispose();
    }
}

let handler = null;

export function initialize(dotNetRef) {
    dotNetRef.invokeMethodAsync('OnResize', window.innerWidth);

    handler = () => {
        dotNetRef.invokeMethodAsync('OnResize', window.innerWidth);
    };
    window.addEventListener('resize', handler);
}

export function dispose() {
    if (handler) {
        window.removeEventListener('resize', handler);
        handler = null;
    }
}

